export default {
	data() {
		return {
			login: false,
			avatarUrl: "../../static/images/avatar.png",
			userInfo: {}
		}
	},
	onLoad() {
		this.getUser();
	},
	methods: {
		navTo(urls){
			if(urls == 'customer/customer'){
				uni.switchTab({
					url:'/pages/'+urls
				})
				this.$store.commit('setCustomerType',1)
			}else{
				uni.navigateTo({
					url:'/pages/'+urls
				})
			}
		},
		getUser(){
			this.$api.Getuserinfobookingapi({},res =>{
				if(res.code == 1000){
					this.userInfo = res.data;
				}
			})
		},
		cName(names){
			// names = names.toString();
			if(names.length > 2){
				return  names.substring(0,2);
			}else{
				return names;
			}
		}
	}
}
